#include <bits/stdc++.h>
using namespace std;
int n,m;
string str;
map<string,bool> isname,rep;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    cin>>n;
    while(n--){
        cin>>str;
        isname[str]=true;
    }
    cin>>m;
    while(m--){
        cin>>str;
        if(!isname[str])
            printf("WRONG\n");
        else if(rep[str])
            printf("REPEAT\n");
        else{
            printf("OK\n");
            rep[str]=true;
        }
    }
    return 0;
}
